import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

function walkSync(dir, filelist = [], baseDir = "") {
  if (!fs.existsSync(dir)) return filelist;
  fs.readdirSync(dir).forEach((file) => {
    const dirFile = path.join(dir, file);
    if (fs.statSync(dirFile).isDirectory()) {
      filelist = walkSync(dirFile, filelist, baseDir);
    } else if (dirFile.endsWith(".ts")) {
      filelist.push({
        fullPath: dirFile,
        relPath: path.relative(baseDir, dirFile).replace(/\\/g, "/")
      });
    }
  });
  return filelist;
}

const bundled = {};

// Siyuan Official Types
const siyuanDir = path.resolve(__dirname, "../node_modules/siyuan/types");
const siyuanFiles = walkSync(siyuanDir, [], siyuanDir);
siyuanFiles.forEach(({ fullPath, relPath }) => {
  bundled["types/" + relPath] = fs.readFileSync(fullPath, "utf-8");
});

// Kits Types
const kitsDir = path.resolve(__dirname, "../node_modules/@frostime/siyuan-plugin-kits/dist/types");
if (fs.existsSync(kitsDir)) {
  const kitsFiles = walkSync(kitsDir, [], kitsDir);
  kitsFiles.forEach(({ fullPath, relPath }) => {
    bundled["types/@frostime/siyuan-plugin-kits/types/" + relPath] = fs.readFileSync(fullPath, "utf-8");
  });
}

const outputContent = `// Automatically generated by scripts/bundle-dts.js
// Do not edit manually.

export const bundledDts: Record<string, string> = ${JSON.stringify(bundled, null, 2)};
`;

const outputPath = path.resolve(__dirname, "../src/utils/bundled-dts.ts");
fs.writeFileSync(outputPath, outputContent, "utf-8");
console.log("✅ Successfully generated src/utils/bundled-dts.ts");
